#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=800005;
int n,m,k,fa[N],h[N],top;//h:树的高 
struct node
{
	int x,y,add;
	/*
	x：被合并的节点（子树的根）
	y：合并后的父节点
	add：标记合并时是否增加了树高（0或1）（不可能>1） 
	*/
} st[N];
struct edge
{
	int u,v;
} g[N];
vector<int> tr[N];//tr[i]存储着线段树编号为i的边
int find(int u)
{
	while(u!=fa[u])
	{
		u=fa[u];
	}
	return u;
}
void fun(int x,int y)
{
	int fx=find(x),fy=find(y);
	if(h[fx]>h[fy]) swap(fx,fy);
	st[++top]=(node){fx,fy,(bool)(h[fx]==h[fy])};
	fa[fx]=fy;
	if(h[fx]==h[fy]) h[fy]++;
}
void update(int u,int l,int r,int L,int R,int x)
{
	if(l>R||r<L) return;
	if(L<=l&&r<=R)
	{
		tr[u].push_back(x);
		return ;
	}
	int mid=(l+r)/2;
	update(u*2,l,mid,L,R,x);
	update(u*2+1,mid+1,r,L,R,x);
}
void query(int u,int l,int r)
{
	int ans=1;
	int tmp=top;
	for(int i=0;i<tr[u].size();i++)
	{
		int num=tr[u][i];
		int a=find(g[num].u);
		int b=find(g[num].v);
		if(a==b)
		{
			for(int j=1;j<=r-l+1;j++) cout<<"No\n";
			ans=0;
			break;
		}
		fun(g[num].u,g[num].v+n);
		fun(g[num].v,g[num].u+n);
	}
	if(ans)
	{
		if(l==r) cout<<"Yes\n";
		else
		{
			int mid=(l+r)/2; 
			query(u*2,l,mid);
			query(u*2+1,mid+1,r);
		}
	}
	while(top>tmp)
	{
		int num=st[top].x;
		h[fa[num]]-=st[top].add;
		fa[num]=num;
		top--;
	}
	return;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>k;
	for(int i=1;i<=m;i++)
	{
		cin>>g[i].u>>g[i].v;
		int l,r;
		cin>>l>>r;
		update(1,1,k,l+1,r,i);
	}
	for(int i=1;i<=2*n;i++)
	{
		fa[i]=i;
		h[i]=1;
	}
	query(1,1,k);
	return 0;
}
